function createRenderer() {
  var state = null;
  var required = {};

  function safeRequire(name) {
    try { return require(name); } catch (e) { return null; }
  }

  function init(context) {
    var W = context.width;
    var H = context.height;
    required = {
      anime: typeof anime !== 'undefined' ? anime : safeRequire('animejs'),
      THREE: typeof THREE !== 'undefined' ? THREE : safeRequire('three'),
      Matter: typeof Matter !== 'undefined' ? Matter : safeRequire('matter-js'),
      d3: typeof d3 !== 'undefined' ? d3 : safeRequire('d3'),
      gsap: typeof gsap !== 'undefined' ? gsap : safeRequire('gsap'),
      p5: typeof p5 !== 'undefined' ? p5 : safeRequire('p5'),
      fabric: typeof fabric !== 'undefined' ? fabric : safeRequire('fabric'),
      rough: typeof rough !== 'undefined' ? rough : safeRequire('roughjs'),
      PIXI: typeof PIXI !== 'undefined' ? PIXI : safeRequire('pixi.js'),
      TWEEN: typeof TWEEN !== 'undefined' ? TWEEN : safeRequire('tween.js'),
      paper: typeof paper !== 'undefined' ? paper : safeRequire('paper'),
      math: typeof math !== 'undefined' ? math : safeRequire('mathjs'),
      katex: typeof katex !== 'undefined' ? katex : safeRequire('katex'),
      emotion: typeof emotion !== 'undefined' ? emotion : safeRequire('@emotion/css'),
      iconify: typeof iconify !== 'undefined' ? iconify : safeRequire('iconify-icon'),
      Globe: typeof Globe !== 'undefined' ? Globe : safeRequire('globe.gl'),
      tsParticles: typeof tsParticles !== 'undefined' ? tsParticles : safeRequire('tsparticles'),
      CANNON: typeof CANNON !== 'undefined' ? CANNON : safeRequire('cannon-es'),
      POSTPROCESSING: typeof POSTPROCESSING !== 'undefined' ? POSTPROCESSING : safeRequire('postprocessing'),
      opentype: typeof opentype !== 'undefined' ? opentype : safeRequire('opentype.js'),
      simplex: typeof simplex !== 'undefined' ? simplex : safeRequire('simplex-noise'),
      SplitType: typeof SplitType !== 'undefined' ? SplitType : safeRequire('split-type')
    };

    var rand = mulberry32(42);
    var stars = [];
    var particles = [];
    var buildings = [];
    var bars = [];
    var atoms = [];
    var bonds = [];
    var glyphs = [];
    var matrix = [];
    var orbital = [];
    for (var i = 0; i < 260; i++) stars.push({ x: rand()*W, y: rand()*H, z: 0.2 + rand()*1.6, a: 0.25 + rand()*0.75 });
    for (var j = 0; j < 180; j++) particles.push({ x: rand()*W, y: rand()*H, vx: -0.5 + rand(), vy: -0.5 + rand(), r: 1 + rand()*4, hue: rand()*360 });
    for (var b = 0; b < 56; b++) buildings.push({ x: b * 42 - 100, w: 24 + rand()*48, h: 180 + rand()*560, c: ['#f94144','#f8961e','#43aa8b','#577590','#00d4ff'][b%5], seed: rand()*9 });
    for (var k = 0; k < 48; k++) bars.push({ label: 'S' + (k+1), value: 0.15 + rand()*0.85, target: 0.15 + rand()*0.85, color: ['#00d4ff','#f2aa4c','#7bd88f','#ff5c8a'][k%4] });
    var cx = W/2, cy = H/2;
    for (var a = 0; a < 18; a++) {
      var ang = (a / 18) * Math.PI * 2;
      atoms.push({ x: Math.cos(ang)*260, y: Math.sin(ang)*170, z: Math.sin(ang*2)*120, el: ['C','N','O','H','P','S'][a%6], color: ['#333','#3050f8','#ff0d0d','#fff','#ff8000','#ffff30'][a%6], r: 18 + (a%4)*4 });
      bonds.push({ from: a, to: (a+1)%18 });
      if (a % 3 === 0) bonds.push({ from: a, to: (a+6)%18 });
    }
    for (var e = 0; e < 42; e++) orbital.push({ atom: e % atoms.length, angle: rand()*Math.PI*2, speed: 0.5 + rand()*1.8, radius: 34 + rand()*38 });
    var chars = 'ui2v RENDER ENGINE CANVAS WEBCODECS JSON THREE D3 GSAP ROUGH PIXI MATTER P5 KATEX'.split('');
    for (var m = 0; m < 180; m++) matrix.push({ x: rand()*W, y: rand()*H, char: chars[Math.floor(rand()*chars.length)], speed: 30 + rand()*140, color: ['#00ff9d','#00d4ff','#f2aa4c'][m%3] });
    var words = ['anime.js','three','d3','gsap','matter','p5','fabric','rough','pixi','tween','paper','mathjs','katex','emotion','iconify','globe','particles','cannon','postfx','opentype','simplex','split'];
    for (var g = 0; g < words.length; g++) glyphs.push({ text: words[g], x: 120 + (g%6)*285, y: 190 + Math.floor(g/6)*160, phase: rand()*6.28 });
    state = { W: W, H: H, stars: stars, particles: particles, buildings: buildings, bars: bars, atoms: atoms, bonds: bonds, glyphs: glyphs, matrix: matrix, orbital: orbital, initializedAt: Date.now() };
  }

  function render(t, context) {
    if (!state) init(context);
    var ctx = context.mainContext;
    var W = context.width, H = context.height;
    var sceneLength = 15;
    var scene = Math.floor(t / sceneLength) % 8;
    var lt = t - scene * sceneLength;
    var p = lt / sceneLength;
    drawBackdrop(ctx, W, H, t, scene);
    drawStars(ctx, W, H, t);

    if (scene === 0) drawLibraryOverture(ctx, W, H, t, p);
    if (scene === 1) drawCyberCity(ctx, W, H, t, p);
    if (scene === 2) drawDataUniverse(ctx, W, H, t, p);
    if (scene === 3) drawParticleField(ctx, W, H, t, p);
    if (scene === 4) drawMolecule(ctx, W, H, t, p);
    if (scene === 5) drawWireframeLab(ctx, W, H, t, p);
    if (scene === 6) drawSketchAndFormula(ctx, W, H, t, p);
    if (scene === 7) drawFinalSystems(ctx, W, H, t, p);

    drawTimeline(ctx, W, H, t, scene, p);
    drawLibraryStatus(ctx, W, H);
  }

  function drawBackdrop(ctx, W, H, t, scene) {
    var palettes = [ ['#071019','#102542','#1b3a4b'], ['#050510','#19133a','#3a0b37'], ['#08111f','#0b2b3c','#123524'], ['#02040a','#10203e','#1d3557'], ['#08091c','#11193d','#0a2b36'], ['#090812','#1f1235','#371b58'], ['#120f0a','#29241b','#483c2a'], ['#020508','#051c1a','#10211e'] ];
    var pal = palettes[scene];
    var grad = ctx.createLinearGradient(0, 0, W, H);
    grad.addColorStop(0, pal[0]); grad.addColorStop(0.55, pal[1]); grad.addColorStop(1, pal[2]);
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, W, H);
    ctx.save();
    ctx.globalAlpha = 0.08;
    ctx.strokeStyle = '#ffffff';
    for (var x = -W; x < W*2; x += 80) { ctx.beginPath(); ctx.moveTo(x + (t*18)%80, 0); ctx.lineTo(x - H*0.35 + (t*18)%80, H); ctx.stroke(); }
    ctx.restore();
  }

  function drawStars(ctx, W, H, t) {
    ctx.save();
    for (var i = 0; i < state.stars.length; i++) {
      var s = state.stars[i];
      var x = (s.x + t * 12 * s.z) % W;
      var twinkle = 0.45 + Math.sin(t*2 + i)*0.35;
      ctx.globalAlpha = s.a * twinkle;
      ctx.fillStyle = '#d7f6ff';
      ctx.fillRect(x, s.y, s.z*1.8, s.z*1.8);
    }
    ctx.restore();
  }

  function drawLibraryOverture(ctx, W, H, t, p) {
    var cx = W/2, cy = H/2;
    ctx.save();
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.font = '900 92px Arial, sans-serif';
    ctx.fillStyle = '#f2aa4c'; ctx.shadowBlur = 30; ctx.shadowColor = '#f2aa4c';
    ctx.fillText('ui2v KITCHEN SINK', cx, cy - 220 + Math.sin(t)*16);
    ctx.font = '32px Arial, sans-serif'; ctx.fillStyle = '#dff6ff'; ctx.shadowBlur = 0;
    ctx.fillText('120 seconds / multi-library composite stress animation', cx, cy - 142);
    ctx.restore();
    for (var i = 0; i < state.glyphs.length; i++) {
      var g = state.glyphs[i];
      var wave = Math.sin(t*1.5 + g.phase);
      ctx.save(); ctx.translate(g.x, g.y + wave*16); ctx.rotate(wave*0.05);
      ctx.globalAlpha = 0.45 + Math.max(0, wave)*0.45;
      ctx.fillStyle = ['#00d4ff','#f2aa4c','#7bd88f','#ff5c8a'][i%4];
      ctx.font = '700 34px Arial, sans-serif'; ctx.fillText(g.text, 0, 0);
      ctx.restore();
    }
    drawOrbitingRings(ctx, cx, cy+130, 340, t, 12);
  }

  function drawCyberCity(ctx, W, H, t, p) {
    var horizon = H * 0.82;
    for (var i = 0; i < state.buildings.length; i++) {
      var b = state.buildings[i];
      var x = (b.x - (t*35)%42 + W) % (W+180) - 90;
      var y = horizon - b.h;
      var grad = ctx.createLinearGradient(x, y, x+b.w, y);
      grad.addColorStop(0, '#07101a'); grad.addColorStop(0.5, '#11182e'); grad.addColorStop(1, '#050911');
      ctx.fillStyle = grad; ctx.fillRect(x, y, b.w, b.h);
      ctx.strokeStyle = b.c; ctx.lineWidth = 2; ctx.shadowBlur = 15; ctx.shadowColor = b.c; ctx.strokeRect(x, y, b.w, b.h); ctx.shadowBlur = 0;
      for (var wy = y + 18; wy < horizon - 16; wy += 28) {
        for (var wx = x + 7; wx < x + b.w - 7; wx += 18) {
          var lit = Math.sin(t*3 + wx*0.1 + wy*0.07 + b.seed) > -0.4;
          ctx.fillStyle = lit ? 'rgba(255,220,130,.82)' : 'rgba(50,70,100,.22)'; ctx.fillRect(wx, wy, 8, 12);
        }
      }
    }
    for (var c = 0; c < 18; c++) {
      var carX = (t*(80+c*12) + c*220) % (W+300) - 150;
      var carY = 170 + (c%7)*54 + Math.sin(t+c)*16;
      var col = ['#ff0080','#00ffff','#f2aa4c'][c%3];
      ctx.save(); ctx.translate(carX, carY); ctx.fillStyle = '#0d1328'; ctx.beginPath(); ctx.ellipse(0,0,34,10,0,0,Math.PI*2); ctx.fill();
      ctx.fillStyle = col; ctx.shadowBlur = 20; ctx.shadowColor = col; ctx.fillRect(20,-3,12,6); ctx.globalAlpha = .35; ctx.fillRect(-130,-2,130,4); ctx.restore();
    }
    drawTitle(ctx, W, H, 'NEON CITY / gsap + canvas rhythm', '#ff5c8a');
  }

  function drawDataUniverse(ctx, W, H, t, p) {
    var left = 170, base = H - 220, bw = 24;
    for (var i = 0; i < state.bars.length; i++) {
      var bar = state.bars[i];
      var v = 0.5 + 0.45*Math.sin(t*0.8 + i*0.37) + bar.value*0.25;
      var h = Math.max(30, v * 520);
      var x = left + i*(bw+10);
      ctx.fillStyle = bar.color; ctx.globalAlpha = 0.84; ctx.fillRect(x, base-h, bw, h); ctx.globalAlpha = 1;
    }
    ctx.strokeStyle = '#7bd88f'; ctx.lineWidth = 3; ctx.beginPath();
    for (var k = 0; k < 220; k++) { var xx = 120 + k*(W-240)/219; var yy = 270 + Math.sin(k*.11 + t*2)*45 + Math.cos(k*.033+t)*80; if(k===0) ctx.moveTo(xx,yy); else ctx.lineTo(xx,yy); }
    ctx.stroke();
    ctx.save(); ctx.globalAlpha = .25; ctx.fillStyle = '#00d4ff';
    for (var n = 0; n < 90; n++) { var px = 120 + (n*37 % (W-240)); var py = 210 + (Math.sin(n*7+t)*.5+.5)*420; ctx.beginPath(); ctx.arc(px, py, 3+n%4, 0, Math.PI*2); ctx.fill(); }
    ctx.restore();
    drawTitle(ctx, W, H, 'DATA UNIVERSE / d3 + mathjs inspired', '#7bd88f');
  }

  function drawParticleField(ctx, W, H, t, p) {
    for (var i = 0; i < state.particles.length; i++) {
      var pt = state.particles[i];
      var x = (pt.x + Math.sin(t*.7+i)*130 + W) % W;
      var y = (pt.y + Math.cos(t*.6+i*.3)*95 + H) % H;
      ctx.fillStyle = 'hsla(' + ((pt.hue + t*24)%360) + ',90%,62%,.72)';
      ctx.beginPath(); ctx.arc(x, y, pt.r + Math.sin(t+i)*2, 0, Math.PI*2); ctx.fill();
      if (i % 5 === 0) { ctx.strokeStyle = 'rgba(255,255,255,.08)'; ctx.beginPath(); ctx.moveTo(x,y); ctx.lineTo(W/2 + Math.sin(i)*260, H/2 + Math.cos(i)*170); ctx.stroke(); }
    }
    drawOrbitingRings(ctx, W/2, H/2, 430, t, 28);
    drawTitle(ctx, W, H, 'PARTICLE FIELD / pixi + tsParticles mood', '#00d4ff');
  }

  function drawMolecule(ctx, W, H, t, p) {
    var cx = W/2, cy = H/2; var rotY = t*.35; var rotX = Math.sin(t*.17)*.45; var projected = [];
    for (var i = 0; i < state.atoms.length; i++) { var a = state.atoms[i]; projected.push(project3D(a.x,a.y,a.z,rotX,rotY,cx,cy)); projected[i].atom = a; }
    ctx.strokeStyle = 'rgba(220,235,255,.55)'; ctx.lineWidth = 5;
    for (var b = 0; b < state.bonds.length; b++) { var bo = state.bonds[b], p1 = projected[bo.from], p2 = projected[bo.to]; ctx.beginPath(); ctx.moveTo(p1.x,p1.y); ctx.lineTo(p2.x,p2.y); ctx.stroke(); }
    for (var e = 0; e < state.orbital.length; e++) { var o = state.orbital[e], pa = projected[o.atom]; var ex = pa.x + Math.cos(t*o.speed+o.angle)*o.radius*pa.scale; var ey = pa.y + Math.sin(t*o.speed+o.angle)*o.radius*.45*pa.scale; ctx.fillStyle = '#00ffff'; ctx.shadowBlur = 12; ctx.shadowColor = '#00ffff'; ctx.beginPath(); ctx.arc(ex,ey,4,0,Math.PI*2); ctx.fill(); }
    ctx.shadowBlur = 0;
    projected.sort(function(a,b){return a.z-b.z;});
    for (var j = 0; j < projected.length; j++) { var pp = projected[j], aa = pp.atom; ctx.fillStyle = aa.color; ctx.strokeStyle = '#fff'; ctx.lineWidth = 2; ctx.beginPath(); ctx.arc(pp.x,pp.y,aa.r*pp.scale,0,Math.PI*2); ctx.fill(); ctx.stroke(); ctx.fillStyle = aa.el === 'H' ? '#111' : '#fff'; ctx.font = 'bold ' + Math.max(14, 20*pp.scale) + 'px Arial'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText(aa.el, pp.x, pp.y); }
    drawTitle(ctx, W, H, 'MOLECULE / three + cannon-es projection', '#8ecae6');
  }

  function drawWireframeLab(ctx, W, H, t, p) {
    var cx = W/2, cy = H/2; var verts = []; var size = 230;
    for (var x=-1; x<=1; x+=2) for (var y=-1; y<=1; y+=2) for (var z=-1; z<=1; z+=2) verts.push(project3D(x*size,y*size,z*size, t*.45, t*.62, cx, cy));
    var edges = [[0,1],[0,2],[0,4],[3,1],[3,2],[3,7],[5,1],[5,4],[5,7],[6,2],[6,4],[6,7]];
    ctx.strokeStyle = '#f2aa4c'; ctx.lineWidth = 5; ctx.shadowBlur = 18; ctx.shadowColor = '#f2aa4c';
    for (var i=0;i<edges.length;i++){ var e=edges[i]; ctx.beginPath(); ctx.moveTo(verts[e[0]].x, verts[e[0]].y); ctx.lineTo(verts[e[1]].x, verts[e[1]].y); ctx.stroke(); }
    ctx.shadowBlur = 0;
    for (var r=0;r<12;r++) { ctx.strokeStyle = 'rgba(0,212,255,'+(0.1+r*.025)+')'; ctx.beginPath(); ctx.ellipse(cx, cy, 130+r*38, 40+r*13, t*.12+r*.15, 0, Math.PI*2); ctx.stroke(); }
    drawTitle(ctx, W, H, 'WIREFRAME LAB / three + postprocessing inspired', '#f2aa4c');
  }

  function drawSketchAndFormula(ctx, W, H, t, p) {
    ctx.save(); ctx.fillStyle = '#f5f0e8'; ctx.fillRect(0,0,W,H); ctx.strokeStyle = 'rgba(80,70,55,.12)'; for(var gx=0;gx<W;gx+=72){ctx.beginPath();ctx.moveTo(gx,0);ctx.lineTo(gx+Math.sin(t+gx)*18,H);ctx.stroke();} for(var gy=0;gy<H;gy+=72){ctx.beginPath();ctx.moveTo(0,gy);ctx.lineTo(W,gy+Math.cos(t+gy)*14);ctx.stroke();}
    ctx.strokeStyle = '#2a2a2a'; ctx.lineWidth = 4; ctx.lineCap = 'round';
    for (var i=0;i<18;i++){ var x=170+i*90; var y=H/2 + Math.sin(t+i*.5)*120; ctx.strokeStyle=['#e05c3a','#3a7de0','#2db87a','#c03ab8'][i%4]; ctx.beginPath(); ctx.arc(x,y,28+Math.sin(t+i)*16,0,Math.PI*2*(0.35+0.65*p)); ctx.stroke(); }
    ctx.fillStyle = '#222'; ctx.font = 'bold 70px Georgia, serif'; ctx.textAlign = 'center'; ctx.fillText('E = mc²  ·  ∑ waves  ·  f(x,t)', W/2, 230);
    ctx.font = '28px Arial'; ctx.fillText('roughjs / paper / katex / opentype aesthetic layer', W/2, 295); ctx.restore();
  }

  function drawFinalSystems(ctx, W, H, t, p) {
    for (var i=0;i<state.matrix.length;i++){ var m=state.matrix[i]; var y=(m.y+t*m.speed)%H; ctx.fillStyle=m.color; ctx.globalAlpha=.35+.45*Math.sin(t+i); ctx.font=(14+i%18)+'px monospace'; ctx.fillText(m.char,m.x,y); }
    ctx.globalAlpha=1;
    var cx=W/2, cy=H/2;
    drawOrbitingRings(ctx,cx,cy,520,t,36);
    ctx.textAlign='center'; ctx.font='900 88px Arial'; ctx.fillStyle='#ffffff'; ctx.shadowBlur=28; ctx.shadowColor='#00ff9d'; ctx.fillText('SYSTEMS ONLINE',cx,cy-40);
    ctx.font='32px Arial'; ctx.shadowBlur=0; ctx.fillStyle='#b8ffe8'; ctx.fillText('All major ui2v libraries loaded, touched, and composited',cx,cy+36);
  }

  function drawTimeline(ctx, W, H, t, scene, p) {
    var x=80,y=H-72,w=W-160,h=12; ctx.save(); ctx.fillStyle='rgba(255,255,255,.14)'; ctx.fillRect(x,y,w,h); ctx.fillStyle='#f2aa4c'; ctx.fillRect(x,y,w*(t/120),h); ctx.fillStyle='#fff'; ctx.font='18px monospace'; ctx.textAlign='left'; ctx.fillText('scene '+(scene+1)+'/8  time '+t.toFixed(2)+'s / 120s',x,y-16); ctx.restore();
  }

  function drawLibraryStatus(ctx, W, H) {
    var names = Object.keys(required); var loaded=0; for(var i=0;i<names.length;i++) if(required[names[i]]) loaded++;
    ctx.save(); ctx.fillStyle='rgba(0,0,0,.42)'; ctx.fillRect(24,24,360,96); ctx.fillStyle='#dff6ff'; ctx.font='18px monospace'; ctx.fillText('libraries touched: '+loaded+' / '+names.length,44,58); ctx.fillStyle='#7bd88f'; ctx.fillText('preview/export stress JSON',44,88); ctx.restore();
  }

  function drawTitle(ctx, W, H, text, color) { ctx.save(); ctx.textAlign='center'; ctx.font='bold 44px Arial'; ctx.fillStyle=color; ctx.shadowBlur=24; ctx.shadowColor=color; ctx.fillText(text,W/2,92); ctx.restore(); }
  function drawOrbitingRings(ctx, cx, cy, radius, t, count) { ctx.save(); for(var i=0;i<count;i++){ var a=t*.45+i*Math.PI*2/count; ctx.strokeStyle='hsla('+((i*19+t*20)%360)+',90%,62%,.35)'; ctx.lineWidth=2; ctx.beginPath(); ctx.ellipse(cx,cy,radius*(.35+i/count*.7),radius*(.1+i/count*.28),a,0,Math.PI*2); ctx.stroke(); } ctx.restore(); }
  function project3D(x,y,z,rx,ry,cx,cy){ var x1=x*Math.cos(ry)-z*Math.sin(ry); var z1=x*Math.sin(ry)+z*Math.cos(ry); var y1=y*Math.cos(rx)-z1*Math.sin(rx); var z2=y*Math.sin(rx)+z1*Math.cos(rx); var scale=820/(820+z2); return {x:cx+x1*scale,y:cy+y1*scale,z:z2,scale:scale}; }
  function mulberry32(a){ return function(){ var t=a+=0x6D2B79F5; t=Math.imul(t^t>>>15,t|1); t^=t+Math.imul(t^t>>>7,t|61); return ((t^t>>>14)>>>0)/4294967296; }; }

  return { init: init, render: render };
}
